## Method 4: Interactive Program (C++)

```cpp
#include <iostream>
#include <cmath>
using namespace std;

int main() {
    double a = 1, b = 2, c = -15;

    double discriminant = b*b - 4*a*c;

    cout << "Equation: " << a << "x^2 + " << b << "x + " << c << " = 0\n";
    cout << "Discriminant: " << discriminant << "\n\n";

    if (discriminant < 0) {
        cout << "No real solutions\n";
    } else if (discriminant == 0) {
        double x = -b / (2*a);
        cout << "One solution: x = " << x << "\n";
    } else {
        double x1 = (-b + sqrt(discriminant)) / (2*a);
        double x2 = (-b - sqrt(discriminant)) / (2*a);
        cout << "Two solutions:\n";
        cout << "x1 = " << x1 << "\n";
        cout << "x2 = " << x2 << "\n";
    }

    return 0;
}
```

---

## ✅ **Answer**

**x = 3** and **x = -5**

**Verification:**
- x = 3: 3² + 2(3) - 15 = 9 + 6 - 15 = 0 ✓
- x = -5: (-5)² + 2(-5) - 15 = 25 - 10 - 15 = 0 ✓
